// This is a single-line comment in TypeScript
// The 'console.log' function prints text to the terminal
// TypeScript can infer types, but we specify ': string' for clarity
// The 'const' keyword means this value cannot be reassigned
const greeting: string = 'Hello, World!';
// Without the type annotation, TypeScript would still know it's a string
const inferredGreeting = 'Hello from TypeScript!';
// Calling the function to display our message
console.log(greeting);
// Another log call showing the inferred variable
console.log(inferredGreeting);
// Expected output:
// Hello, World!
// Hello from TypeScript!
